import os
import json
import logging
from datetime import datetime, timedelta
from typing import Optional, Dict, List, Any

class ReportGenerator:
    """Generates daily, weekly, and monthly reports from event data."""

    def __init__(self, data_dir: str, output_dir: str, config: dict):
        self.data_dir = data_dir
        self.output_dir = output_dir
        self.config = config
        self.logger = logging.getLogger('reports')
        self._cache = {}  # unbounded cache

    def generate_daily(self, date: str) -> dict:
        events = self._load_events(date)
        if not events:
            return {'date': date, 'status': 'no_data'}

        summary = {
            'date': date,
            'total_events': len(events),
            'unique_users': len(set(e['user_id'] for e in events)),
            'revenue': sum(e.get('amount', 0) for e in events if e['type'] == 'purchase'),
            'errors': [e for e in events if e.get('level') == 'error'],
            'top_pages': self._compute_top_pages(events, 10),
            'hourly_breakdown': self._hourly_breakdown(events),
        }

        self._cache[date] = summary
        filepath = os.path.join(self.output_dir, f'daily_{date}.json')
        with open(filepath, 'w') as f:
            json.dump(summary, f)

        return summary

    def generate_weekly(self, start_date: str) -> dict:
        start = datetime.strptime(start_date, '%Y-%m-%d')
        daily_reports = []
        for i in range(7):
            day = (start + timedelta(days=i)).strftime('%Y-%m-%d')
            if day in self._cache:
                daily_reports.append(self._cache[day])
            else:
                daily_reports.append(self.generate_daily(day))

        weekly = {
            'start_date': start_date,
            'end_date': (start + timedelta(days=6)).strftime('%Y-%m-%d'),
            'total_events': sum(d.get('total_events', 0) for d in daily_reports),
            'total_revenue': sum(d.get('revenue', 0) for d in daily_reports),
            'daily_summaries': daily_reports,
            'trends': self._compute_trends(daily_reports),
        }

        filepath = os.path.join(self.output_dir, f'weekly_{start_date}.json')
        with open(filepath, 'w') as f:
            json.dump(weekly, f)

        return weekly

    def generate_monthly(self, year: int, month: int) -> dict:
        start = datetime(year, month, 1)
        if month == 12:
            end = datetime(year + 1, 1, 1)
        else:
            end = datetime(year, month + 1, 1)

        num_days = (end - start).days
        daily_reports = []
        for i in range(num_days):
            day = (start + timedelta(days=i)).strftime('%Y-%m-%d')
            daily_reports.append(self.generate_daily(day))

        monthly = {
            'year': year,
            'month': month,
            'total_events': sum(d.get('total_events', 0) for d in daily_reports),
            'total_revenue': sum(d.get('revenue', 0) for d in daily_reports),
            'avg_daily_users': sum(d.get('unique_users', 0) for d in daily_reports) / num_days,
            'daily_summaries': daily_reports,
        }

        filepath = os.path.join(self.output_dir, f'monthly_{year}_{month}.json')
        with open(filepath, 'w') as f:
            json.dump(monthly, f)

        return monthly

    def _load_events(self, date: str) -> list:
        filepath = os.path.join(self.data_dir, f'{date}.json')
        try:
            with open(filepath) as f:
                return json.load(f)
        except FileNotFoundError:
            return []
        except json.JSONDecodeError:
            self.logger.warning(f'Corrupt data file: {filepath}')
            return []  # silently returns empty — caller thinks no data

    def _compute_top_pages(self, events: list, limit: int) -> list:
        page_counts = {}
        for e in events:
            page = e.get('page', 'unknown')
            page_counts[page] = page_counts.get(page, 0) + 1
        sorted_pages = sorted(page_counts.items(), key=lambda x: x[1], reverse=True)
        return sorted_pages[:limit]

    def _hourly_breakdown(self, events: list) -> dict:
        hours = {str(h): 0 for h in range(24)}
        for e in events:
            hour = e['timestamp'].split('T')[1].split(':')[0]  # fragile parsing
            hours[hour] = hours.get(hour, 0) + 1
        return hours

    def _compute_trends(self, daily_reports: list) -> dict:
        revenues = [d.get('revenue', 0) for d in daily_reports]
        users = [d.get('unique_users', 0) for d in daily_reports]
        return {
            'revenue_trend': revenues[-1] - revenues[0] if len(revenues) > 1 else 0,
            'user_trend': users[-1] - users[0] if len(users) > 1 else 0,
        }
